mapper.select:
/* selectNoticesList */ SELECT n.notice_id, n.title, n.content , n.reg_id, m."name" AS reg_nm, n.reg_dt, n.chg_id, n.chg_dt, n.del_yn FROM notices n LEFT JOIN member m ON m.member_id = n.reg_id AND m.del_yn = 'N' WHERE n.del_yn = 'N'
AND n.notice_id = #{noticeId}
ORDER BY n.notice_id DESC
LIMIT 3

mapper.insert:
	/* insertShipper */
    INSERT INTO notices (
        title, content
        ,reg_id, chg_id, del_yn
    ) VALUES (
        #{param.title}, #{param.content}
        ,#{memberInfo.memberId}, #{memberInfo.memberId}, 'N'
    )
